def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 5):
                    val = ((ratio - a) ** 6) / (a * b * 1.1 + 1)
                    priority += val * np.sin(ratio * b / (a + 0.5)) * ((-1) ** (a+b))
            priority += (np.cosh(ratio - 7) * np.sin(ratio * 1.3)) ** 1.8
            for c in range(1, 5):
                priority -= np.tan(ratio / (c + 0.7)) * 0.4
        elif 4 < ratio <= 7:
            for p in range(1, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p) / (q + 0.3)
                    priority += np.tanh(term) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 4) * 3
            if bin_cap < item * 1.05:
                priority += np.sqrt(item * bin_cap) * 1.2
            else:
                priority -= np.sin(ratio * 5) * 2
        elif 2 <= ratio <= 4:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2) * np.sin(r * ratio * 1.1)
            priority = (s * np.cos(9 * ratio)) - np.log(ratio) * 7 + np.tanh(5 * (4 - ratio)) * 1.7
            for k in range(1, 4):
                priority += ((ratio - 2) ** k) * np.sin(k * i * ratio) / (k + 0.5)
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.3)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-1.8 / (ratio + 0.03))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 1.1) * ((ratio - 1) ** m) / (m ** 0.9 + 0.3)
            priority += np.log(bin_cap + ratio) * 2
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3.5)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.6
            else:
                priority /= (np.sqrt(bin_cap + 2.5) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.5) * 0.8
            if bin_cap < item * 0.8:
                priority += np.sqrt(item * bin_cap) * 2
            else:
                priority -= np.exp(-ratio * 2.2) * 1.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 4) * np.cos(k * ratio * 2.5)
            priority = s + 1.5 / (bin_cap + 4)
            if int(item * 1.6) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 15):
                s += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 6)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7
            priority += np.sin(bin_cap * ratio * 4) * 3
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
            priority -= np.cos(bin_cap / (item + 0.1)) * 2
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.5) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.5) * 0.8
        if i % 2 == 0:
            for z in range(1, 4):
                priority += np.tanh(np.sin(ratio * i * z)) * (0.2 + 0.1 * z)
        else:
            for z in range(1, 4):
                priority -= np.tanh(np.cos(ratio * i * z)) * (0.2 + 0.1 * z)
        priorities[i] = priority
    return priorities
